"use client";

import { MoonIcon, Redo2Icon, SunIcon, Undo2Icon } from "@/lib/hugeicons";
import { useEditor, useEditorState } from "@mcut/react";
import { Button } from "@/components/ui/button";
import { Kbd } from "@/components/ui/kbd";
import { Tooltip, TooltipContent, TooltipTrigger } from "@/components/ui/tooltip";
import { cn } from "@/lib/utils";
import { useEditorUI, type EditorMode } from "./editor-ui";
import { ExportDialog } from "./export-dialog";
import { MainMenu } from "./main-menu";
import { ShortcutsDialog } from "./shortcuts-dialog";

function ProjectName() {
  const engine = useEditor();
  const name = useEditorState((s) => s.project.name);
  return (
    <input
      value={name}
      aria-label="Project name"
      className="w-48 rounded-md border border-transparent bg-transparent px-2 py-0.5 text-center text-xs font-medium outline-none hover:border-border focus:border-foreground/20"
      onChange={(e) =>
        engine.dispatch(
          { type: "updateProject", name: e.target.value || "Untitled" },
          { history: false },
        )
      }
    />
  );
}

function ThemeToggle() {
  const { theme, setTheme } = useEditorUI();
  return (
    <Tooltip>
      <TooltipTrigger
        render={
          <Button
            variant="ghost"
            size="icon-sm"
            aria-label="Toggle theme"
            onClick={() => setTheme(theme === "dark" ? "light" : "dark")}
          />
        }
      >
        {theme === "dark" ? <SunIcon /> : <MoonIcon />}
      </TooltipTrigger>
      <TooltipContent>{theme === "dark" ? "Light theme" : "Dark theme"}</TooltipContent>
    </Tooltip>
  );
}

const MODES: Array<{ id: EditorMode; label: string }> = [
  { id: "edit", label: "Edit" },
  { id: "multicam", label: "Multicam" },
  { id: "thumbnail", label: "Thumbnail" },
];

/** The editing-mode switch: modes re-emphasize affordances, never the document. */
function ModeSwitch() {
  const { mode, setMode } = useEditorUI();
  return (
    <div className="flex items-center gap-0.5 rounded-lg bg-foreground/5 p-0.5">
      {MODES.map(({ id, label }) => (
        <button
          key={id}
          type="button"
          className={cn(
            "rounded-md px-2 py-0.5 text-xs font-medium transition-colors",
            mode === id
              ? "bg-card text-foreground shadow-xs"
              : "text-muted-foreground hover:text-foreground",
          )}
          onClick={() => setMode(id)}
        >
          {label}
        </button>
      ))}
    </div>
  );
}

/** Slim top chrome: brand menu, history, project name, theme, shortcuts, export. */
export function EditorToolbar() {
  const engine = useEditor();
  const canUndo = useEditorState((s) => s.canUndo);
  const canRedo = useEditorState((s) => s.canRedo);

  return (
    <div className="flex h-11 shrink-0 items-center gap-1.5 px-3">
      <MainMenu />
      <Tooltip>
        <TooltipTrigger
          render={
            <Button variant="ghost" size="icon-sm" disabled={!canUndo} onClick={() => engine.undo()} aria-label="Undo" />
          }
        >
          <Undo2Icon />
        </TooltipTrigger>
        <TooltipContent>
          Undo <Kbd>⌘Z</Kbd>
        </TooltipContent>
      </Tooltip>
      <Tooltip>
        <TooltipTrigger
          render={
            <Button variant="ghost" size="icon-sm" disabled={!canRedo} onClick={() => engine.redo()} aria-label="Redo" />
          }
        >
          <Redo2Icon />
        </TooltipTrigger>
        <TooltipContent>
          Redo <Kbd>⇧⌘Z</Kbd>
        </TooltipContent>
      </Tooltip>

      <div className="flex flex-1 items-center justify-center gap-3">
        <ProjectName />
        <ModeSwitch />
      </div>

      <span className="hidden items-center gap-1 text-2xs text-muted-foreground sm:flex">
        <Kbd>⌘K</Kbd> commands
      </span>
      <ThemeToggle />
      <ShortcutsDialog />
      <ExportDialog />
    </div>
  );
}

import { cn } from "@/lib/utils";

export function BrandMark({
  className,
  wordmark = false,
}: {
  className?: string;
  wordmark?: boolean;
}) {
  return (
    <span
      aria-label="mcut"
      className={cn(
        "inline-flex select-none items-center text-3xl font-bold leading-none italic",
        className,
      )}
      style={{
        fontFamily: "var(--font-logo), 'Instrument Serif', Georgia, serif",
      }}
    >
      {wordmark ? "mcut" : "m"}
    </span>
  );
}

"use client";

import { useState } from "react";
import {
  CameraIcon,
  CheckIcon,
  ChevronFirstIcon,
  ChevronLastIcon,
  EyeIcon,
  MagnetIcon,
  MaximizeIcon,
  PauseIcon,
  PlayIcon,
  RatioIcon,
  StepBackIcon,
  StepForwardIcon,
  Volume2Icon,
  VolumeXIcon,
} from "@/lib/hugeicons";
import { toast } from "sonner";
import { useEditorContext, useEditorState, usePlayback, type PreviewQuality } from "@mcut/react";
import { getProjectDurationMs } from "@mcut/timeline";
import { Button } from "@/components/ui/button";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { Kbd } from "@/components/ui/kbd";
import { Tooltip, TooltipContent, TooltipTrigger } from "@/components/ui/tooltip";
import { useEditorUI, type TimelineEditMode, type TimelineTool } from "./editor-ui";
import { formatTimecode } from "./format";
import { captureViewportStill } from "./viewport-capture";

/** Premiere-style pointer tools; letters double as their shortcuts. */
const TIMELINE_TOOLS: Array<{ id: TimelineTool; label: string; hint: string; key: string }> = [
  { id: "select", label: "Select", hint: "move / trim", key: "V" },
  { id: "ripple", label: "Ripple", hint: "trim + close gaps", key: "B" },
  { id: "roll", label: "Roll", hint: "move the cut", key: "R" },
  { id: "slip", label: "Slip", hint: "shift source in place", key: "Y" },
  { id: "slide", label: "Slide", hint: "move between neighbors", key: "U" },
];

const EDIT_MODES: Array<{ id: TimelineEditMode; label: string; hint: string }> = [
  { id: "normal", label: "Normal", hint: "drops never collide" },
  { id: "overwrite", label: "Overwrite", hint: "drops clear their landing range" },
  { id: "insert", label: "Insert", hint: "drops ripple everything right" },
];

const ASPECT_PRESETS = [
  { label: "16:9 — Landscape", width: 1920, height: 1080 },
  { label: "9:16 — Portrait", width: 1080, height: 1920 },
  { label: "1:1 — Square", width: 1080, height: 1080 },
  { label: "4:5 — Social", width: 1080, height: 1350 },
  { label: "21:9 — Cinema", width: 2560, height: 1080 },
];

/** Preview-only raster quality (export always renders full resolution). */
const QUALITY_PRESETS: Array<{ label: string; hint: string; value: PreviewQuality }> = [
  { label: "Auto", hint: "fit preview", value: "auto" },
  { label: "720p", hint: "performance", value: 720 },
  { label: "1080p", hint: "balanced", value: 1080 },
  { label: "Full", hint: "project size", value: "full" },
];

const CAPTURE_PRESETS = [
  { label: "Project resolution", hint: "1x", scale: 1 },
  { label: "High resolution", hint: "2x", scale: 2 },
  { label: "Ultra high resolution", hint: "4x", scale: 4 },
];

function IconButton({
  label,
  shortcut,
  onClick,
  active,
  children,
  disabled,
}: {
  label: string;
  shortcut?: string;
  onClick: () => void;
  active?: boolean;
  disabled?: boolean;
  children: React.ReactNode;
}) {
  return (
    <Tooltip>
      <TooltipTrigger
        render={
          <Button
            variant={active ? "secondary" : "ghost"}
            size="icon-sm"
            onClick={onClick}
            disabled={disabled}
            aria-label={label}
          />
        }
      >
        {children}
      </TooltipTrigger>
      <TooltipContent className="flex items-center gap-1.5">
        {label}
        {shortcut && <Kbd>{shortcut}</Kbd>}
      </TooltipContent>
    </Tooltip>
  );
}

function Timecode() {
  const currentTimeMs = usePlayback((s) => s.currentTimeMs);
  const durationMs = useEditorState((s) => getProjectDurationMs(s.project));
  return (
    <span className="min-w-30 text-center font-mono text-xs tabular-nums text-muted-foreground select-none">
      <span className="text-foreground">{formatTimecode(currentTimeMs)}</span>
      <span className="px-0.5 opacity-50">/</span>
      {formatTimecode(durationMs)}
    </span>
  );
}

/**
 * CapCut-style transport strip under the preview: skip/step/play, timecode,
 * aspect presets, snap magnet, mute, fullscreen.
 */
export function TransportBar() {
  const { engine, pool } = useEditorContext();
  const isPlaying = usePlayback((s) => s.isPlaying);
  const muted = usePlayback((s) => s.muted);
  const fps = useEditorState((s) => s.project.fps);
  const {
    snapEnabled,
    setSnapEnabled,
    timelineTool,
    setTimelineTool,
    editMode,
    setEditMode,
    autoCrossfade,
    setAutoCrossfade,
    previewQuality,
    setPreviewQuality,
  } = useEditorUI();
  const [capturingScale, setCapturingScale] = useState<number | null>(null);
  const frameMs = 1000 / fps;

  const seekBy = (deltaMs: number) =>
    engine.seek(engine.playback.state.currentTimeMs + deltaMs);

  const captureStill = async (scale: number) => {
    setCapturingScale(scale);
    try {
      const still = await captureViewportStill(engine, { source: pool, scale });
      toast.success(
        `Captured ${still.width}×${still.height} still to the media bin`,
      );
    } catch (error) {
      toast.error(error instanceof Error ? error.message : "Could not capture still");
    } finally {
      setCapturingScale(null);
    }
  };

  return (
    <div className="flex h-11 shrink-0 items-center gap-0.5 px-2">
      <div className="mr-1 flex items-center gap-px rounded-md bg-muted/40 p-0.5">
        {TIMELINE_TOOLS.map((tool) => (
          <Tooltip key={tool.id}>
            <TooltipTrigger
              render={
                <Button
                  variant={timelineTool === tool.id ? "secondary" : "ghost"}
                  size="icon-sm"
                  className="size-6 font-mono text-2xs"
                  onClick={() => setTimelineTool(tool.id)}
                  aria-label={`${tool.label} tool`}
                />
              }
            >
              {tool.key}
            </TooltipTrigger>
            <TooltipContent className="flex items-center gap-1.5">
              {tool.label} — {tool.hint}
              <Kbd>{tool.key}</Kbd>
            </TooltipContent>
          </Tooltip>
        ))}
      </div>
      <IconButton
        label={snapEnabled ? "Snapping on" : "Snapping off"}
        shortcut="N"
        active={snapEnabled}
        onClick={() => setSnapEnabled(!snapEnabled)}
      >
        <MagnetIcon />
      </IconButton>
      <DropdownMenu>
        <DropdownMenuTrigger
          render={
            <Button
              variant={editMode === "normal" ? "ghost" : "secondary"}
              size="sm"
              className="h-7 px-2 font-mono text-2xs uppercase"
              aria-label="Edit mode"
              title="Edit mode for drops and inserts"
            />
          }
        >
          {editMode}
        </DropdownMenuTrigger>
        <DropdownMenuContent align="start">
          <DropdownMenuLabel>Edit mode</DropdownMenuLabel>
          <DropdownMenuSeparator />
          {EDIT_MODES.map((mode) => (
            <DropdownMenuItem key={mode.id} onClick={() => setEditMode(mode.id)}>
              {editMode === mode.id ? (
                <CheckIcon className="size-3.5" />
              ) : (
                <span className="size-3.5" />
              )}
              {mode.label}
              <span className="ml-auto pl-3 font-mono text-2xs text-muted-foreground">
                {mode.hint}
              </span>
            </DropdownMenuItem>
          ))}
          <DropdownMenuSeparator />
          <DropdownMenuItem onClick={() => setAutoCrossfade(!autoCrossfade)}>
            {autoCrossfade ? <CheckIcon className="size-3.5" /> : <span className="size-3.5" />}
            Auto-crossfade
            <span className="ml-auto pl-3 font-mono text-2xs text-muted-foreground">
              dissolve on push
            </span>
          </DropdownMenuItem>
        </DropdownMenuContent>
      </DropdownMenu>
      <DropdownMenu>
        <DropdownMenuTrigger
          render={<Button variant="ghost" size="icon-sm" aria-label="Canvas size" title="Canvas size" />}
        >
          <RatioIcon />
        </DropdownMenuTrigger>
        <DropdownMenuContent align="start">
          <DropdownMenuLabel>Canvas</DropdownMenuLabel>
          <DropdownMenuSeparator />
          {ASPECT_PRESETS.map((preset) => (
            <DropdownMenuItem
              key={preset.label}
              onClick={() =>
                engine.dispatch({
                  type: "updateProject",
                  width: preset.width,
                  height: preset.height,
                })
              }
            >
              {preset.label}
              <span className="ml-auto pl-3 font-mono text-2xs text-muted-foreground">
                {preset.width}×{preset.height}
              </span>
            </DropdownMenuItem>
          ))}
        </DropdownMenuContent>
      </DropdownMenu>
      <DropdownMenu>
        <DropdownMenuTrigger
          render={
            <Button
              variant="ghost"
              size="icon-sm"
              aria-label="Preview quality"
              title="Preview quality"
            />
          }
        >
          <EyeIcon />
        </DropdownMenuTrigger>
        <DropdownMenuContent align="start">
          <DropdownMenuLabel>Preview quality</DropdownMenuLabel>
          <DropdownMenuSeparator />
          {QUALITY_PRESETS.map((preset) => (
            <DropdownMenuItem key={preset.label} onClick={() => setPreviewQuality(preset.value)}>
              {previewQuality === preset.value ? (
                <CheckIcon className="size-3.5" />
              ) : (
                <span className="size-3.5" />
              )}
              {preset.label}
              <span className="ml-auto pl-3 font-mono text-2xs text-muted-foreground">
                {preset.hint}
              </span>
            </DropdownMenuItem>
          ))}
        </DropdownMenuContent>
      </DropdownMenu>

      <div className="flex flex-1 items-center justify-center gap-0.5">
        <IconButton label="Go to start" onClick={() => engine.seek(0)}>
          <ChevronFirstIcon />
        </IconButton>
        <IconButton label="Previous frame" shortcut="←" onClick={() => seekBy(-frameMs)}>
          <StepBackIcon />
        </IconButton>
        <IconButton
          label={isPlaying ? "Pause" : "Play"}
          shortcut="Space"
          onClick={() => (isPlaying ? engine.pause() : engine.play())}
        >
          <span className="flex size-7 items-center justify-center rounded-full bg-primary text-primary-foreground [&_svg]:size-3.5">
            {isPlaying ? <PauseIcon /> : <PlayIcon className="translate-x-px" />}
          </span>
        </IconButton>
        <IconButton label="Next frame" shortcut="→" onClick={() => seekBy(frameMs)}>
          <StepForwardIcon />
        </IconButton>
        <IconButton
          label="Go to end"
          onClick={() => engine.seek(getProjectDurationMs(engine.project))}
        >
          <ChevronLastIcon />
        </IconButton>
        <Timecode />
      </div>

      <IconButton label={muted ? "Unmute" : "Mute"} onClick={() => engine.setMuted(!muted)}>
        {muted ? <VolumeXIcon className="text-destructive" /> : <Volume2Icon />}
      </IconButton>
      <DropdownMenu>
        <DropdownMenuTrigger
          render={
            <Button
              variant="ghost"
              size="icon-sm"
              aria-label="Capture still"
              title="Capture still"
              disabled={capturingScale !== null}
            />
          }
        >
          <CameraIcon />
        </DropdownMenuTrigger>
        <DropdownMenuContent align="end">
          <DropdownMenuLabel>Capture still</DropdownMenuLabel>
          <DropdownMenuSeparator />
          {CAPTURE_PRESETS.map((preset) => (
            <DropdownMenuItem
              key={preset.scale}
              disabled={capturingScale !== null}
              onClick={() => void captureStill(preset.scale)}
            >
              {preset.label}
              <span className="ml-auto pl-3 font-mono text-2xs text-muted-foreground">
                {capturingScale === preset.scale ? "saving" : preset.hint}
              </span>
            </DropdownMenuItem>
          ))}
        </DropdownMenuContent>
      </DropdownMenu>
      <IconButton
        label="Fullscreen preview"
        onClick={() => {
          document.querySelector("[data-mcut-player]")?.requestFullscreen?.().catch(() => {});
        }}
      >
        <MaximizeIcon />
      </IconButton>
    </div>
  );
}

"use client";

import { renderFrame, type FrameSource } from "@mcut/compositor";
import { createAssetFromFile, getActiveMediaItems, type PreviewMediaPool } from "@mcut/media";
import type { AssetRef, EditorEngine } from "@mcut/timeline";
import { ensureProjectFontsLoaded } from "./font-library";
import { saveAssetBlob } from "./persistence";

export interface ViewportStill {
  asset: AssetRef;
  file: File;
  width: number;
  height: number;
}

export interface CaptureViewportStillOptions {
  scale?: number;
  source?: FrameSource | PreviewMediaPool;
}

function slugPart(value: string): string {
  return (
    value
      .trim()
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, "-")
      .replace(/^-+|-+$/g, "") || "mcut"
  );
}

function timePart(timeMs: number): string {
  const totalSeconds = Math.max(0, Math.floor(timeMs / 1000));
  const ms = Math.max(0, Math.round(timeMs % 1000));
  const seconds = totalSeconds % 60;
  const minutes = Math.floor(totalSeconds / 60) % 60;
  const hours = Math.floor(totalSeconds / 3600);
  return `${hours.toString().padStart(2, "0")}-${minutes
    .toString()
    .padStart(2, "0")}-${seconds.toString().padStart(2, "0")}-${ms.toString().padStart(3, "0")}`;
}

async function canvasToPngFile(canvas: HTMLCanvasElement, filename: string): Promise<File> {
  const blob = await new Promise<Blob | null>((resolve) => canvas.toBlob(resolve, "image/png"));
  if (!blob) throw new Error("Could not encode PNG");
  return new File([blob], filename, { type: "image/png" });
}

/**
 * Render the current playhead frame into a PNG, register it as a normal image
 * asset, and persist the blob so it survives reload with the rest of the bin.
 */
export async function captureViewportStill(
  engine: EditorEngine,
  options: CaptureViewportStillOptions = {},
): Promise<ViewportStill> {
  const project = engine.project;
  const timeMs = engine.playback.state.currentTimeMs;
  const scale = Math.max(1, Math.min(4, Math.round(options.scale ?? 1)));
  const width = Math.max(1, Math.round(project.width * scale));
  const height = Math.max(1, Math.round(project.height * scale));
  const canvas = document.createElement("canvas");
  canvas.width = width;
  canvas.height = height;
  const ctx = canvas.getContext("2d");
  if (!ctx) throw new Error("Could not create capture canvas");

  const source = options.source;
  if (source && "sync" in source) {
    source.sync(getActiveMediaItems(project, timeMs), {
      isPlaying: false,
      playbackRate: engine.playback.state.playbackRate,
      masterVolume: engine.playback.state.volume,
      muted: true,
    });
  }

  await ensureProjectFontsLoaded(project);
  ctx.setTransform(scale, 0, 0, scale, 0, 0);
  renderFrame(ctx, project, timeMs, { source });

  const suffix = scale === 1 ? "" : `-${scale}x`;
  const file = await canvasToPngFile(
    canvas,
    `${slugPart(project.name)}-${timePart(timeMs)}${suffix}.png`,
  );
  const asset = await createAssetFromFile(file);
  engine.dispatch({ type: "addAsset", asset }, { history: false });
  await saveAssetBlob(asset, file);
  return { asset, file, width, height };
}

"use client";

import { useRef, useState } from "react";
import { useMutation, useQuery } from "@tanstack/react-query";
import { DownloadIcon, TriangleAlertIcon } from "@/lib/hugeicons";
import {
  exportProject,
  getExportSupport,
  listContainerFormats,
  type ContainerFormatId,
  type ExportProgress,
} from "@mcut/media";
import { useEditor, useEditorState } from "@mcut/react";
import { getProjectDurationMs } from "@mcut/timeline";
import { cn } from "@/lib/utils";
import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Progress } from "@/components/ui/progress";
import { Spinner } from "./editor-primitives";
import { collectProjectFontExports, ensureProjectFontsLoaded } from "./font-library";

const PHASE_LABEL: Record<ExportProgress["phase"], string> = {
  audio: "Mixing audio",
  video: "Rendering frames",
  finalize: "Finalizing file",
};

function downloadBlob(blob: Blob, filename: string) {
  const url = URL.createObjectURL(blob);
  const anchor = document.createElement("a");
  anchor.href = url;
  anchor.download = filename;
  anchor.click();
  setTimeout(() => URL.revokeObjectURL(url), 10_000);
}

/**
 * Deterministic client-side export: the shared compositor renders every
 * frame from exact decoded samples, WebCodecs encodes, Mediabunny muxes.
 */
export function ExportDialog() {
  const engine = useEditor();
  const [open, setOpen] = useState(false);
  const [format, setFormat] = useState<ContainerFormatId>("mp4");
  const formats = listContainerFormats();
  const formatLabel = formats.find((f) => f.id === format)?.label ?? format.toUpperCase();
  const [progress, setProgress] = useState<ExportProgress | null>(null);
  const durationMs = useEditorState((s) => getProjectDurationMs(s.project));
  const projectName = useEditorState((s) => s.project.name);

  const support = useQuery({
    queryKey: ["mcut-export-support", format],
    queryFn: () => getExportSupport(format),
    enabled: open,
    staleTime: Infinity,
  });

  const abortRef = useRef<AbortController | null>(null);
  const exportMutation = useMutation({
    mutationFn: async () => {
      setProgress({ progress: 0, phase: "audio" });
      engine.pause();
      const controller = new AbortController();
      abortRef.current = controller;
      // Text frames render with whatever face is loaded — make sure every
      // referenced font is in document.fonts (main-thread fallback path) and
      // collect the faces the export worker registers in its own scope.
      await ensureProjectFontsLoaded(engine.project);
      const fonts = await collectProjectFontExports(engine.project);
      return exportProject(engine.project, {
        format,
        fonts,
        onProgress: setProgress,
        signal: controller.signal,
      });
    },
    onSuccess: (result) => {
      downloadBlob(result.blob, `${projectName || "export"}.${result.extension}`);
      setProgress(null);
    },
    onError: () => setProgress(null),
    onSettled: () => {
      abortRef.current = null;
    },
  });
  const exportError =
    exportMutation.isError && !(exportMutation.error instanceof DOMException && exportMutation.error.name === "AbortError")
      ? exportMutation.error
      : null;

  const busy = exportMutation.isPending;
  const unsupported = support.data ? !support.data.video : false;

  return (
    <>
      <Button
        size="sm"
        onClick={() => setOpen(true)}
        disabled={durationMs === 0}
        title="Export video"
        data-mcut-export-trigger=""
      >
        <DownloadIcon /> Export
      </Button>
      <Dialog open={open} onOpenChange={(next) => !busy && setOpen(next)}>
        <DialogContent showCloseButton={!busy}>
          <DialogHeader>
            <DialogTitle>Export video</DialogTitle>
            <DialogDescription>
              Rendered entirely in your browser with WebCodecs — nothing is uploaded.
            </DialogDescription>
          </DialogHeader>

          <div className="flex flex-col gap-4">
            <div className="flex items-center gap-2">
              <span className="w-16 text-xs text-muted-foreground">Format</span>
              <div className="flex flex-1 gap-1">
                {formats.map((option) => (
                  <Button
                    key={option.id}
                    size="xs"
                    variant={format === option.id ? "secondary" : "ghost"}
                    className={cn("flex-1", format === option.id && "font-semibold")}
                    disabled={busy}
                    onClick={() => setFormat(option.id)}
                  >
                    {option.label}
                  </Button>
                ))}
              </div>
            </div>

            {unsupported && (
              <p className="flex items-start gap-2 rounded-xl bg-destructive/10 p-3 text-xs text-destructive">
                <TriangleAlertIcon className="mt-0.5 size-4 shrink-0" />
                This browser can&apos;t encode {formatLabel} with WebCodecs. Try Chrome or
                Edge, or switch formats.
              </p>
            )}
            {support.data && support.data.video && !support.data.audio && (
              <p className="text-xs text-muted-foreground">
                Audio encoding is unavailable in this browser; the export will be silent.
              </p>
            )}

            {busy && progress && (
              <div className="flex flex-col gap-2">
                <Progress value={Math.round(progress.progress * 100)} />
                <p className="text-center text-xs text-muted-foreground">
                  {PHASE_LABEL[progress.phase]} — {Math.round(progress.progress * 100)}%
                </p>
              </div>
            )}

            {exportError && (
              <p className="text-xs text-destructive">
                Export failed: {exportError instanceof Error ? exportError.message : "unknown error"}
              </p>
            )}
          </div>

          <DialogFooter>
            {busy ? (
              <Button variant="ghost" onClick={() => abortRef.current?.abort()}>
                Cancel
              </Button>
            ) : (
              <Button variant="ghost" onClick={() => setOpen(false)}>
                Close
              </Button>
            )}
            <Button disabled={busy || unsupported || durationMs === 0} onClick={() => exportMutation.mutate()}>
              {busy ? <Spinner /> : <DownloadIcon />}
              {busy ? "Exporting…" : `Export ${formatLabel}`}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </>
  );
}

