"use client";

import {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useRef,
  useState,
  useSyncExternalStore,
  type ReactNode,
} from "react";
import type { PreviewQuality } from "@mcut/react";
import { clamp } from "./math";

/** A live drop ghost while dragging media over the timeline. */
export interface DropPreview {
  /** Target track id, or "new-track" for the phantom top lane. */
  trackId: string;
  startMs: number;
  durationMs: number;
  label: string;
}

// ---------------------------------------------------------------------------
// Drag overlay stores
// ---------------------------------------------------------------------------
// Drop ghost and snap guide update on every pointermove during a drag. They
// live in tiny external stores (not React context state) so a drag move
// re-renders only the overlay components that subscribe via useDropPreview/
// useSnapGuideMs — never the whole editor tree.

interface OverlayStore<T> {
  get: () => T;
  set: (value: T) => void;
  subscribe: (listener: () => void) => () => void;
}

function createOverlayStore<T>(initial: T, equals: (a: T, b: T) => boolean): OverlayStore<T> {
  let value = initial;
  const listeners = new Set<() => void>();
  return {
    get: () => value,
    set: (next: T) => {
      if (equals(value, next)) return;
      value = next;
      for (const listener of listeners) listener();
    },
    subscribe: (listener: () => void) => {
      listeners.add(listener);
      return () => listeners.delete(listener);
    },
  };
}

function dropPreviewEquals(a: DropPreview | null, b: DropPreview | null): boolean {
  if (a === b) return true;
  if (!a || !b) return false;
  return (
    a.trackId === b.trackId &&
    a.startMs === b.startMs &&
    a.durationMs === b.durationMs &&
    a.label === b.label
  );
}

interface DragOverlayStores {
  dropPreview: OverlayStore<DropPreview | null>;
  snapGuide: OverlayStore<number | null>;
}

const DragOverlayContext = createContext<DragOverlayStores | null>(null);

function useDragOverlayStores(): DragOverlayStores {
  const stores = useContext(DragOverlayContext);
  if (!stores) throw new Error("drag overlay hooks must be used inside <EditorUIProvider>");
  return stores;
}

/** The live drop ghost, or null when no media drag is over the timeline. */
export function useDropPreview(): DropPreview | null {
  const { dropPreview } = useDragOverlayStores();
  return useSyncExternalStore(dropPreview.subscribe, dropPreview.get, () => null);
}

/** The snap guide line (timeline ms), or null when nothing is snapping. */
export function useSnapGuideMs(): number | null {
  const { snapGuide } = useDragOverlayStores();
  return useSyncExternalStore(snapGuide.subscribe, snapGuide.get, () => null);
}

export type EditorTheme = "dark" | "light";

/**
 * Editing modes are VIEWS, not document state: they re-emphasize affordances
 * (multicam = layout bank + 1–9 switching; thumbnail = safe areas + cover
 * tools) over the same project.
 */
export type EditorMode = "edit" | "multicam" | "thumbnail";

/**
 * Timeline pointer tools (Premiere's tool palette): select is the default
 * move/trim tool; ripple/roll change what the trim handles do; slip/slide
 * change what dragging the clip body does.
 */
export type TimelineTool = "select" | "ripple" | "roll" | "slip" | "slide";

/**
 * Placement mode for inserts and drops (Kdenlive's taxonomy): normal rejects
 * collisions, overwrite clears the landing range, insert ripples everything
 * after the point to the right.
 */
export type TimelineEditMode = "normal" | "overwrite" | "insert";

export interface EditorUIValue {
  /** Editor color theme (warm grey light/dark; tokens in globals.css). */
  theme: EditorTheme;
  setTheme: (value: EditorTheme) => void;
  /** Current editing mode (session-scoped; not persisted). */
  mode: EditorMode;
  setMode: (value: EditorMode) => void;
  /** Layout whose slots are being edited on the canvas (multicam mode). */
  editingLayoutId: string | null;
  setEditingLayoutId: (value: string | null) => void;
  /**
   * Slot edit state: index of the slot (within the editing layout) whose
   * properties the inspector shows. Shared so the canvas overlay and the
   * properties panel select and style the same slot.
   */
  editingSlotIndex: number | null;
  setEditingSlotIndex: (value: number | null) => void;
  /** Text element being edited INLINE on the canvas (double-click to enter). */
  editingTextId: string | null;
  setEditingTextId: (value: string | null) => void;
  /** Drop targets the thumbnail panel publishes for the canvas (thumbnail mode). */
  thumbnailSlots: Array<{ rect: { x: number; y: number; w: number; h: number }; label: string }> | null;
  setThumbnailSlots: (
    value: Array<{ rect: { x: number; y: number; w: number; h: number }; label: string }> | null,
  ) => void;
  /** Timeline zoom. */
  pxPerMs: number;
  setPxPerMs: (value: number) => void;
  /** Zoom keeping `anchorMs` under the same screen x (used by ⌘+wheel). */
  zoomBy: (factor: number, anchorMs?: number) => void;
  snapEnabled: boolean;
  setSnapEnabled: (value: boolean) => void;
  /** Active timeline pointer tool (session-scoped). */
  timelineTool: TimelineTool;
  setTimelineTool: (value: TimelineTool) => void;
  /** Placement mode for inserts/drops (session-scoped). */
  editMode: TimelineEditMode;
  setEditMode: (value: TimelineEditMode) => void;
  /** Drop a dissolve when a dragged clip is pushed flush against a neighbor. */
  autoCrossfade: boolean;
  setAutoCrossfade: (value: boolean) => void;
  /** Preview raster resolution ('auto' fits the pane; numbers cap the short side). */
  previewQuality: PreviewQuality;
  setPreviewQuality: (value: PreviewQuality) => void;
  /** Publish the drop ghost (read it via useDropPreview — it's not in this context). */
  setDropPreview: (value: DropPreview | null) => void;
  /** The timeline's horizontal scroll container (for zoom anchoring/auto-scroll). */
  timelineScrollRef: React.RefObject<HTMLDivElement | null>;
  /** Publish the snap guide line (read it via useSnapGuideMs). */
  setSnapGuideMs: (value: number | null) => void;
}

export const MIN_PX_PER_MS = 0.004;
export const MAX_PX_PER_MS = 0.6;
/** Left header gutter width inside the timeline, px. */
export const TIMELINE_HEADER_WIDTH = 288;

const EditorUIContext = createContext<EditorUIValue | null>(null);

const PREFS_KEY = "mcut:ui";

function loadPrefs(): {
  pxPerMs?: number;
  snapEnabled?: boolean;
  autoCrossfade?: boolean;
  theme?: EditorTheme;
  previewQuality?: PreviewQuality;
} {
  if (typeof window === "undefined") return {};
  try {
    return JSON.parse(window.localStorage.getItem(PREFS_KEY) ?? "{}");
  } catch {
    return {};
  }
}

function isPreviewQuality(value: unknown): value is PreviewQuality {
  return value === "auto" || value === "full" || (typeof value === "number" && value > 0);
}

export function EditorUIProvider({ children }: { children: ReactNode }) {
  const [pxPerMs, setPxPerMsState] = useState(0.05);
  const [snapEnabled, setSnapEnabledState] = useState(true);
  const [timelineTool, setTimelineTool] = useState<TimelineTool>("select");
  const [editMode, setEditMode] = useState<TimelineEditMode>("normal");
  const [autoCrossfade, setAutoCrossfadeState] = useState(false);
  const [previewQuality, setPreviewQualityState] = useState<PreviewQuality>("auto");
  const [theme, setThemeState] = useState<EditorTheme>("dark");
  const [mode, setModeState] = useState<EditorMode>("edit");
  const [editingLayoutId, setEditingLayoutIdState] = useState<string | null>(null);
  const [editingSlotIndex, setEditingSlotIndex] = useState<number | null>(null);
  const [editingTextId, setEditingTextId] = useState<string | null>(null);
  const setEditingLayoutId = useCallback((value: string | null) => {
    setEditingLayoutIdState(value);
    setEditingSlotIndex(null); // slot selection is scoped to one layout
  }, []);
  const [thumbnailSlots, setThumbnailSlots] = useState<
    Array<{ rect: { x: number; y: number; w: number; h: number }; label: string }> | null
  >(null);
  const setMode = useCallback((value: EditorMode) => {
    setModeState(value);
    // Leaving a mode always exits slot editing.
    setEditingLayoutIdState(null);
    setEditingSlotIndex(null);
    setEditingTextId(null);
  }, []);
  const [overlayStores] = useState<DragOverlayStores>(() => ({
    dropPreview: createOverlayStore<DropPreview | null>(null, dropPreviewEquals),
    snapGuide: createOverlayStore<number | null>(null, Object.is),
  }));
  const setDropPreview = useCallback(
    (value: DropPreview | null) => overlayStores.dropPreview.set(value),
    [overlayStores],
  );
  const setSnapGuideMs = useCallback(
    (value: number | null) => overlayStores.snapGuide.set(value),
    [overlayStores],
  );
  const timelineScrollRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    // Apply persisted prefs after hydration (a lazy initializer would make
    // the server and client first paints disagree).
    const timer = setTimeout(() => {
      const prefs = loadPrefs();
      if (prefs.pxPerMs) setPxPerMsState(clampZoom(prefs.pxPerMs));
      if (prefs.snapEnabled !== undefined) setSnapEnabledState(prefs.snapEnabled);
      if (prefs.autoCrossfade !== undefined) setAutoCrossfadeState(prefs.autoCrossfade);
      if (isPreviewQuality(prefs.previewQuality)) setPreviewQualityState(prefs.previewQuality);
      if (prefs.theme === "light" || prefs.theme === "dark") setThemeState(prefs.theme);
    }, 0);
    return () => clearTimeout(timer);
  }, []);

  const persist = (patch: Record<string, unknown>) => {
    try {
      window.localStorage.setItem(PREFS_KEY, JSON.stringify({ ...loadPrefs(), ...patch }));
    } catch {
      // Private mode: prefs just don't persist.
    }
  };

  const setPxPerMs = useCallback((value: number) => {
    const clamped = clampZoom(value);
    setPxPerMsState(clamped);
    persist({ pxPerMs: clamped });
  }, []);

  const setTheme = useCallback((value: EditorTheme) => {
    setThemeState(value);
    persist({ theme: value });
  }, []);

  const setSnapEnabled = useCallback((value: boolean) => {
    setSnapEnabledState(value);
    persist({ snapEnabled: value });
  }, []);

  const setAutoCrossfade = useCallback((value: boolean) => {
    setAutoCrossfadeState(value);
    persist({ autoCrossfade: value });
  }, []);

  const setPreviewQuality = useCallback((value: PreviewQuality) => {
    setPreviewQualityState(value);
    persist({ previewQuality: value });
  }, []);

  const zoomBy = useCallback(
    (factor: number, anchorMs?: number) => {
      setPxPerMsState((previous) => {
        const next = clampZoom(previous * factor);
        const scroller = timelineScrollRef.current;
        if (scroller && anchorMs !== undefined) {
          // Keep anchorMs under the same screen x after the zoom.
          const anchorX = anchorMs * previous - scroller.scrollLeft;
          requestAnimationFrame(() => {
            scroller.scrollLeft = anchorMs * next - anchorX;
          });
        }
        persist({ pxPerMs: next });
        return next;
      });
    },
    [],
  );

  // Memoized so a provider re-render doesn't re-render every consumer; only
  // actual value changes do.
  const value = useMemo<EditorUIValue>(
    () => ({
      theme,
      setTheme,
      mode,
      setMode,
      editingLayoutId,
      setEditingLayoutId,
      editingSlotIndex,
      setEditingSlotIndex,
      editingTextId,
      setEditingTextId,
      thumbnailSlots,
      setThumbnailSlots,
      pxPerMs,
      setPxPerMs,
      zoomBy,
      snapEnabled,
      setSnapEnabled,
      timelineTool,
      setTimelineTool,
      editMode,
      setEditMode,
      autoCrossfade,
      setAutoCrossfade,
      previewQuality,
      setPreviewQuality,
      setDropPreview,
      timelineScrollRef,
      setSnapGuideMs,
    }),
    [
      theme,
      setTheme,
      mode,
      setMode,
      editingLayoutId,
      setEditingLayoutId,
      editingSlotIndex,
      editingTextId,
      thumbnailSlots,
      pxPerMs,
      setPxPerMs,
      zoomBy,
      snapEnabled,
      setSnapEnabled,
      timelineTool,
      editMode,
      autoCrossfade,
      setAutoCrossfade,
      previewQuality,
      setPreviewQuality,
      setDropPreview,
      setSnapGuideMs,
    ],
  );

  return (
    <EditorUIContext.Provider value={value}>
      <DragOverlayContext.Provider value={overlayStores}>
        {children}
      </DragOverlayContext.Provider>
    </EditorUIContext.Provider>
  );
}

function clampZoom(value: number): number {
  return clamp(value, MIN_PX_PER_MS, MAX_PX_PER_MS);
}

export function useEditorUI(): EditorUIValue {
  const context = useContext(EditorUIContext);
  if (!context) throw new Error("useEditorUI must be used inside <EditorUIProvider>");
  return context;
}

/** 90500 → "1:30.5" (minutes:seconds.tenths). */
export function formatTimecode(ms: number): string {
  const total = Math.max(0, ms);
  const minutes = Math.floor(total / 60_000);
  const seconds = Math.floor((total % 60_000) / 1000);
  const tenths = Math.floor((total % 1000) / 100);
  return `${minutes}:${String(seconds).padStart(2, "0")}.${tenths}`;
}

/** Ruler label: 90000 → "1:30". */
export function formatRulerLabel(ms: number): string {
  const minutes = Math.floor(ms / 60_000);
  const seconds = Math.round((ms % 60_000) / 1000);
  return `${minutes}:${String(seconds).padStart(2, "0")}`;
}

/** 90500 → "1:31" rounded duration for badges. */
export function formatDurationBadge(ms: number): string {
  return formatRulerLabel(Math.round(ms / 1000) * 1000);
}

import { parseProject, type AssetRef, type Project } from "@mcut/timeline";
import {
  isMediaStoreSupported,
  loadMediaBlob,
  pruneMediaBlobs,
  saveMediaBlob,
} from "@mcut/media";

/**
 * Local project library: each project is autosaved into an IndexedDB store
 * keyed by project id (with denormalized metadata for a future projects
 * screen); media blobs go to OPFS keyed by content hash (deduped, relinkable)
 * with an IndexedDB fallback keyed by asset id for unhashed files and
 * unsupported browsers. Blob pruning considers every saved project, not just
 * the active one. On load, object URLs are recreated and the asset `src`s
 * rewritten — `src` is a runtime binding, `hash` is the identity.
 */

const DB_NAME = "mcut-editor";
const DB_VERSION = 2;
const KV_STORE = "kv";
const ASSET_STORE = "assets";
const PROJECT_STORE = "projects";
/** v1 single-slot autosave key, migrated into PROJECT_STORE on upgrade. */
const LEGACY_PROJECT_KEY = "project";
const ACTIVE_PROJECT_KEY = "activeProjectId";

interface StoredAsset {
  id: string;
  blob: Blob;
}

/** One saved project. Metadata is denormalized so listing never parses JSON. */
interface StoredProject {
  id: string;
  name: string;
  createdMs: number;
  updatedMs: number;
  durationMs: number;
  assetCount: number;
  /** Poster frame for the projects screen; generation is wired up later. */
  thumbnail?: Blob;
  project: unknown;
}

/** What a projects screen needs to render a card — everything but the JSON. */
export type ProjectListEntry = Omit<StoredProject, "project">;

function projectDurationMs(project: Project): number {
  let end = 0;
  for (const track of project.tracks) {
    for (const element of track.elements) {
      end = Math.max(end, element.startMs + element.durationMs);
    }
  }
  return end;
}

function hasContent(project: Project): boolean {
  return (
    Object.keys(project.assets).length > 0 ||
    project.tracks.some((track) => track.elements.length > 0)
  );
}

function toStoredProject(project: Project, previous?: StoredProject): StoredProject {
  const now = Date.now();
  return {
    id: project.id,
    name: project.name,
    createdMs: previous?.createdMs ?? now,
    updatedMs: now,
    durationMs: projectDurationMs(project),
    assetCount: Object.keys(project.assets).length,
    thumbnail: previous?.thumbnail,
    project: JSON.parse(JSON.stringify(project)),
  };
}

function openDb(): Promise<IDBDatabase> {
  return new Promise((resolve, reject) => {
    const request = indexedDB.open(DB_NAME, DB_VERSION);
    request.onupgradeneeded = () => {
      const db = request.result;
      const tx = request.transaction!;
      if (!db.objectStoreNames.contains(KV_STORE)) db.createObjectStore(KV_STORE);
      if (!db.objectStoreNames.contains(ASSET_STORE)) {
        db.createObjectStore(ASSET_STORE, { keyPath: "id" });
      }
      if (!db.objectStoreNames.contains(PROJECT_STORE)) {
        db.createObjectStore(PROJECT_STORE, { keyPath: "id" });
        // Migrate the v1 single-slot autosave into the library.
        const kv = tx.objectStore(KV_STORE);
        const read = kv.get(LEGACY_PROJECT_KEY);
        read.onsuccess = () => {
          const raw = read.result;
          if (!raw) return;
          try {
            const project = parseProject(raw);
            tx.objectStore(PROJECT_STORE).put(toStoredProject(project));
            kv.put(project.id, ACTIVE_PROJECT_KEY);
            kv.delete(LEGACY_PROJECT_KEY);
          } catch {
            // Unparseable legacy snapshot — drop it rather than block the upgrade.
            kv.delete(LEGACY_PROJECT_KEY);
          }
        };
      }
    };
    request.onsuccess = () => resolve(request.result);
    request.onerror = () => reject(request.error);
  });
}

function txDone(tx: IDBTransaction): Promise<void> {
  return new Promise((resolve, reject) => {
    tx.oncomplete = () => resolve();
    tx.onerror = () => reject(tx.error);
    tx.onabort = () => reject(tx.error);
  });
}

function getRequest<T>(request: IDBRequest<T>): Promise<T> {
  return new Promise((resolve, reject) => {
    request.onsuccess = () => resolve(request.result);
    request.onerror = () => reject(request.error);
  });
}

/**
 * Ask the browser not to evict our IndexedDB/OPFS data under storage
 * pressure. Safe to call repeatedly; browsers may grant silently or prompt.
 */
export async function requestPersistentStorage(): Promise<boolean> {
  try {
    return (await navigator.storage?.persist?.()) ?? false;
  } catch {
    return false;
  }
}

/** Upsert the project into the library and mark it active. */
export async function saveProjectSnapshot(project: Project): Promise<void> {
  // Don't litter the library with the empty project every page boot creates.
  if (!hasContent(project)) return;
  const db = await openDb();
  let keepHashes = new Set<string>();
  try {
    const previousTx = db.transaction(PROJECT_STORE, "readonly");
    const previous = (await getRequest(previousTx.objectStore(PROJECT_STORE).get(project.id))) as
      | StoredProject
      | undefined;

    const saveTx = db.transaction([KV_STORE, PROJECT_STORE], "readwrite");
    saveTx.objectStore(PROJECT_STORE).put(toStoredProject(project, previous));
    saveTx.objectStore(KV_STORE).put(project.id, ACTIVE_PROJECT_KEY);
    await txDone(saveTx);

    const refsTx = db.transaction([PROJECT_STORE, ASSET_STORE], "readonly");
    const projectStore = refsTx.objectStore(PROJECT_STORE);
    const assetStore = refsTx.objectStore(ASSET_STORE);
    const [stored, keys] = await Promise.all([
      getRequest(projectStore.getAll()) as Promise<StoredProject[]>,
      getRequest(assetStore.getAllKeys()),
    ]);
    const refs = collectReferencedAssets(stored);
    keepHashes = refs.keepHashes;
    const staleKeys = keys.filter((key) => !refs.keepAssetIds.has(String(key)));
    if (staleKeys.length > 0) {
      const pruneTx = db.transaction(ASSET_STORE, "readwrite");
      const pruneStore = pruneTx.objectStore(ASSET_STORE);
      for (const key of staleKeys) pruneStore.delete(key);
      await txDone(pruneTx);
    }
  } finally {
    db.close();
  }
  await pruneMediaBlobs(keepHashes).catch(() => 0);
}

/** Union of asset ids/hashes across every saved project. */
function collectReferencedAssets(
  stored: StoredProject[],
): { keepAssetIds: Set<string>; keepHashes: Set<string> } {
  const keepAssetIds = new Set<string>();
  const keepHashes = new Set<string>();
  for (const record of stored) {
    const assets = (record.project as Project | undefined)?.assets ?? {};
    for (const [id, asset] of Object.entries(assets)) {
      keepAssetIds.add(id);
      if (asset.hash) keepHashes.add(asset.hash);
    }
  }
  return { keepAssetIds, keepHashes };
}

export async function saveAssetBlob(asset: AssetRef | string, blob: Blob): Promise<void> {
  const assetId = typeof asset === "string" ? asset : asset.id;
  const hash = typeof asset === "string" ? undefined : asset.hash;
  if (hash && isMediaStoreSupported()) {
    const stored = await saveMediaBlob(hash, blob).catch(() => false);
    if (stored) return;
  }
  const db = await openDb();
  try {
    const tx = db.transaction(ASSET_STORE, "readwrite");
    tx.objectStore(ASSET_STORE).put({ id: assetId, blob } satisfies StoredAsset);
    await txDone(tx);
  } finally {
    db.close();
  }
}

/** Saved projects, most recently edited first. */
export async function listProjects(): Promise<ProjectListEntry[]> {
  const db = await openDb();
  try {
    const tx = db.transaction(PROJECT_STORE, "readonly");
    const stored = (await getRequest(tx.objectStore(PROJECT_STORE).getAll())) as StoredProject[];
    return stored
      .map((record) => ({
        id: record.id,
        name: record.name,
        createdMs: record.createdMs,
        updatedMs: record.updatedMs,
        durationMs: record.durationMs,
        assetCount: record.assetCount,
        ...(record.thumbnail ? { thumbnail: record.thumbnail } : {}),
      }))
      .sort((a, b) => b.updatedMs - a.updatedMs);
  } catch {
    return [];
  } finally {
    db.close();
  }
}

export interface RestoredSession {
  project: Project;
  /** Asset ids whose media blobs were not found (their clips render empty). */
  missingAssetIds: string[];
}

/**
 * Load a saved project by id, recreating object URLs for stored media blobs
 * and rewriting asset `src`s. Returns `null` when nothing useful is saved.
 */
export async function loadProject(id: string): Promise<RestoredSession | null> {
  const db = await openDb();
  try {
    const projectTx = db.transaction(PROJECT_STORE, "readonly");
    const record = (await getRequest(projectTx.objectStore(PROJECT_STORE).get(id))) as
      | StoredProject
      | undefined;
    if (!record) return null;
    const project = parseProject(record.project);
    if (!hasContent(project)) return null;

    const assetTx = db.transaction(ASSET_STORE, "readonly");
    const stored = (await getRequest(assetTx.objectStore(ASSET_STORE).getAll())) as StoredAsset[];
    const blobs = new Map(stored.map((s) => [s.id, s.blob]));
    const missingAssetIds: string[] = [];
    const assets = { ...project.assets };
    for (const [assetId, asset] of Object.entries(assets)) {
      // OPFS by content hash first (stable identity), then legacy IDB by id.
      const blob =
        (asset.hash ? await loadMediaBlob(asset.hash).catch(() => null) : null) ??
        blobs.get(assetId);
      if (blob) {
        assets[assetId] = { ...asset, src: URL.createObjectURL(blob) };
      } else if (asset.src.startsWith("blob:")) {
        missingAssetIds.push(assetId);
      }
    }
    return { project: { ...project, assets }, missingAssetIds };
  } catch {
    return null;
  } finally {
    db.close();
  }
}

async function getActiveProjectId(): Promise<string | null> {
  const db = await openDb();
  try {
    const tx = db.transaction(KV_STORE, "readonly");
    const id = await getRequest(tx.objectStore(KV_STORE).get(ACTIVE_PROJECT_KEY));
    return typeof id === "string" ? id : null;
  } catch {
    return null;
  } finally {
    db.close();
  }
}

/** Load the most recently active project (the v1 "restore session" behavior). */
export async function loadSavedSession(): Promise<RestoredSession | null> {
  const activeId = await getActiveProjectId();
  if (activeId) {
    const restored = await loadProject(activeId);
    if (restored) return restored;
  }
  // Active pointer missing or stale — fall back to the newest project.
  const [newest] = await listProjects();
  return newest ? loadProject(newest.id) : null;
}

/** Remove a project from the library and prune blobs it alone referenced. */
export async function deleteProject(id: string): Promise<void> {
  const db = await openDb();
  let keepHashes = new Set<string>();
  try {
    const activeTx = db.transaction(KV_STORE, "readonly");
    const activeId = await getRequest(activeTx.objectStore(KV_STORE).get(ACTIVE_PROJECT_KEY));

    const deleteTx = db.transaction([KV_STORE, PROJECT_STORE], "readwrite");
    deleteTx.objectStore(PROJECT_STORE).delete(id);
    if (activeId === id) deleteTx.objectStore(KV_STORE).delete(ACTIVE_PROJECT_KEY);
    await txDone(deleteTx);

    const refsTx = db.transaction([PROJECT_STORE, ASSET_STORE], "readonly");
    const projectStore = refsTx.objectStore(PROJECT_STORE);
    const assetStore = refsTx.objectStore(ASSET_STORE);
    const [stored, keys] = await Promise.all([
      getRequest(projectStore.getAll()) as Promise<StoredProject[]>,
      getRequest(assetStore.getAllKeys()),
    ]);
    const refs = collectReferencedAssets(stored);
    keepHashes = refs.keepHashes;
    const staleKeys = keys.filter((key) => !refs.keepAssetIds.has(String(key)));
    if (staleKeys.length > 0) {
      const pruneTx = db.transaction(ASSET_STORE, "readwrite");
      const pruneStore = pruneTx.objectStore(ASSET_STORE);
      for (const key of staleKeys) pruneStore.delete(key);
      await txDone(pruneTx);
    }
  } finally {
    db.close();
  }
  await pruneMediaBlobs(keepHashes).catch(() => 0);
}

/** Store a poster frame for a project card (no-op if the project is gone). */
export async function saveProjectThumbnail(id: string, thumbnail: Blob): Promise<void> {
  const db = await openDb();
  try {
    const readTx = db.transaction(PROJECT_STORE, "readonly");
    const record = (await getRequest(readTx.objectStore(PROJECT_STORE).get(id))) as
      | StoredProject
      | undefined;
    if (!record) return;
    const writeTx = db.transaction(PROJECT_STORE, "readwrite");
    writeTx.objectStore(PROJECT_STORE).put({ ...record, thumbnail });
    await txDone(writeTx);
  } finally {
    db.close();
  }
}

/**
 * v1-compat: forget the active project. With the library in place this only
 * deletes the project being replaced, not every saved project.
 */
export async function clearSavedSession(): Promise<void> {
  const activeId = await getActiveProjectId();
  if (activeId) await deleteProject(activeId);
}

"use client";

import { useEffect, useSyncExternalStore } from "react";
import type { ExportFontFaceInit } from "@mcut/media";
