export interface EditorAction {
  /** Stable id, "category.verb" ("selection.select-all"). */
  id: string;
  label: string;
  category: ActionCategory;
  shortcut?: Shortcut | Shortcut[];
  /** Icon for the palette/menus (optional). */
  icon?: ComponentType<{ className?: string }>;
  /** Show in the ⌘K palette. Default true. */
  palette?: boolean;
  /**
   * Delegate behavior to a user-level operator (@mcut/editor) — the same
   * definition agents call over MCP. `run`/`enabled` are synthesized from
   * the operator unless explicitly overridden; `input` supplies the
   * operator's payload (static or derived from the action context).
   */
  operator?: {
    id: string;
    input?: Record<string, unknown> | ((context: ActionContext) => Record<string, unknown>);
  };
  enabled?: (context: ActionContext) => boolean;
  run?: (context: ActionContext) => void;
}

const registry = new Map<string, EditorAction>();

function operatorInput(action: EditorAction, context: ActionContext): unknown {
  const input = action.operator?.input;
  return typeof input === "function" ? input(context) : (input ?? {});
}

export function defineAction(action: EditorAction): EditorAction {
  if (registry.has(action.id)) {
    if (process.env.NODE_ENV !== "production") {
      registry.set(action.id, action);
      return action;
    }
    throw new Error(`editor action "${action.id}" is already defined`);
  }
  if (!action.operator && !action.run) {
    throw new Error(`editor action "${action.id}" needs an operator or a run()`);
  }
  registry.set(action.id, action);
  return action;
}

export function listEditorActions(): EditorAction[] {
  return [...registry.values()];
}

export function getEditorAction(id: string): EditorAction | undefined {
  return registry.get(id);
}

export function isActionEnabled(action: EditorAction, context: ActionContext): boolean {
  try {
    if (action.enabled) return action.enabled(context);
    if (action.operator) {
      const operator = editorOperators.get(action.operator.id);
      if (!operator) return false;
      const status = operator.enabled?.(
        { engine: context.engine },
        operatorInput(action, context),
      );
      if (status === undefined) return true;
      return typeof status === "boolean" ? status : status.enabled;
    }
    return true;
  } catch {
    return false;
  }
}

/** Run by id or reference; no-ops when missing or disabled. */
export function runEditorAction(idOrAction: string | EditorAction, context: ActionContext): void {
  const action = typeof idOrAction === "string" ? registry.get(idOrAction) : idOrAction;
  if (!action || !isActionEnabled(action, context)) return;
  try {
    if (action.run) action.run(context);
    else if (action.operator) {
      void editorOperators.run(
        action.operator.id,
        { engine: context.engine },
        operatorInput(action, context),
      );
    }
  } catch {
    // Engine rejections (CommandError) are non-fatal in UI paths.
  }
}

export function shortcutsOf(action: EditorAction): Shortcut[] {
  if (!action.shortcut) return [];
  return Array.isArray(action.shortcut) ? action.shortcut : [action.shortcut];
}

export function matchShortcut(
  event: Pick<KeyboardEvent, "key" | "metaKey" | "ctrlKey" | "shiftKey" | "altKey"> & {
    code?: string;
  },
  shortcut: Shortcut,
): boolean {
  const key = event.key.length === 1 ? event.key.toLowerCase() : event.key;
  const wantedKey = shortcut.key.length === 1 ? shortcut.key.toLowerCase() : shortcut.key;
  // macOS Option+letter types a special character ("˚" for ⌥K), so alt
  // shortcuts also match on the physical key code.
  const codeMatches =
    shortcut.alt &&
    /^[a-z]$/.test(wantedKey) &&
    event.code === `Key${wantedKey.toUpperCase()}`;
  if (key !== wantedKey && !codeMatches) return false;
  const meta = event.metaKey || event.ctrlKey;
  if (meta !== Boolean(shortcut.meta)) return false;
  if (event.shiftKey !== Boolean(shortcut.shift)) return false;
  if (event.altKey !== Boolean(shortcut.alt)) return false;
  return true;
}

/** Action matching a keyboard event (first match wins). */
export function actionForEvent(
  event: Pick<KeyboardEvent, "key" | "metaKey" | "ctrlKey" | "shiftKey" | "altKey">,
): EditorAction | undefined {
  for (const action of registry.values()) {
    if (shortcutsOf(action).some((shortcut) => matchShortcut(event, shortcut))) {
      return action;
    }
  }
  return undefined;
}

const KEY_GLYPHS: Record<string, string> = {
  " ": "Space",
  ArrowLeft: "←",
  ArrowRight: "→",
  ArrowUp: "↑",
  ArrowDown: "↓",
  Backspace: "⌫",
  Delete: "⌦",
  Escape: "Esc",
  Home: "Home",
  End: "End",
};

/** "⇧⌘Z"-style display string (first shortcut when several). */
export function formatShortcut(shortcut: Shortcut | Shortcut[] | undefined): string {
  if (!shortcut) return "";
  const first = Array.isArray(shortcut) ? shortcut[0] : shortcut;
  if (!first) return "";
  const key = KEY_GLYPHS[first.key] ?? first.key.toUpperCase();
  return `${first.alt ? "⌥" : ""}${first.shift ? "⇧" : ""}${first.meta ? "⌘" : ""}${key}`;
}

import {
  createElementId,
  findNearestFreeSlot,
  getElementLocation,
  type EditorEngine,
  type ElementId,
  type TimelineElement,
} from "@mcut/timeline";

/**
 * The editor's internal clipboard: serialized clips with their original
 * track positions, pasted relative to the playhead. Survives within the
 * session; OS-clipboard JSON interop is a parity-list follow-up.
 */

interface ClipboardEntry {
  /** Deep-cloned element, id stripped (regenerated on paste). */
  element: Omit<TimelineElement, "id">;
  /** Model track index at copy time (pasted to the same lane when possible). */
  trackIndex: number;
  /** Offset from the earliest copied element's startMs. */
  offsetMs: number;
}

export interface EditorClipboard {
  entries: ClipboardEntry[];
}

export const editorClipboard: EditorClipboard = { entries: [] };

const ENVELOPE_VERSION = 1;

interface ClipboardEnvelope {
  mcutClipboard: number;
  entries: ClipboardEntry[];
}

function isEnvelope(value: unknown): value is ClipboardEnvelope {
  return (
    typeof value === "object" &&
    value !== null &&
    (value as ClipboardEnvelope).mcutClipboard === ENVELOPE_VERSION &&
    Array.isArray((value as ClipboardEnvelope).entries)
  );
}

/** Mirror the internal clipboard to the OS clipboard (cross-tab/project paste). */
function writeOsClipboard(): void {
  const envelope: ClipboardEnvelope = {
    mcutClipboard: ENVELOPE_VERSION,
    entries: editorClipboard.entries,
  };
  navigator.clipboard?.writeText(JSON.stringify(envelope)).catch(() => {
    // Permission denied / insecure context: internal clipboard still works.
  });
}

/** Copy the selection. Returns how many clips were copied. */
export function copySelection(engine: EditorEngine): number {
  const located = engine.selection.elementIds
    .map((id) => getElementLocation(engine.project, id))
    .filter((location) => location !== undefined);
  if (located.length === 0) return 0;
  const earliestMs = Math.min(...located.map((l) => l.element.startMs));
  editorClipboard.entries = located.map(({ element, trackIndex }) => {
    const { id, ...clone } = JSON.parse(JSON.stringify(element)) as TimelineElement;
    void id;
    return { element: clone, trackIndex, offsetMs: element.startMs - earliestMs };
  });
  writeOsClipboard();
  return editorClipboard.entries.length;
}

export function cutSelection(engine: EditorEngine): number {
  const count = copySelection(engine);
  if (count === 0) return 0;
  engine.transact(() => {
    for (const elementId of engine.selection.elementIds) {
      try {
        engine.dispatch({ type: "removeElement", elementId });
      } catch {
        // Already removed.
      }
    }
  });
  return count;
}

/**
 * Paste at the playhead: the earliest copied clip lands there, the rest keep
 * their relative offsets and lanes (clamped to existing tracks, nudged to
 * free space). The pasted clips become the selection.
 */
export function pasteAtPlayhead(engine: EditorEngine): ElementId[] {
  if (editorClipboard.entries.length === 0) return [];
  const anchorMs = Math.max(0, Math.round(engine.playback.state.currentTimeMs));
  const pastedIds: ElementId[] = [];
  engine.transact(() => {
    for (const entry of editorClipboard.entries) {
      const project = engine.project;
      const trackIndex = Math.min(entry.trackIndex, project.tracks.length - 1);
      const track = project.tracks[trackIndex]!;
      const id = createElementId();
      const startMs = findNearestFreeSlot(
        track,
        anchorMs + entry.offsetMs,
        entry.element.durationMs,
      );
      try {
        engine.dispatch({
          type: "addElement",
          trackId: track.id,
          element: { ...entry.element, id, startMs },
        });
        pastedIds.push(id);
      } catch {
        // Asset was removed since copy, or no room: skip this clip.
      }
    }
  });
  if (pastedIds.length > 0) engine.select(pastedIds);
  return pastedIds;
}

/**
 * Paste from wherever has content: an mcut envelope on the OS clipboard
 * (written by copy in any mcut tab) wins; the internal clipboard is the
 * fallback when reading is denied or holds something else.
 */
export async function pasteAtPlayheadFromAnywhere(engine: EditorEngine): Promise<ElementId[]> {
  try {
    const text = await navigator.clipboard?.readText();
    if (text) {
      const parsed: unknown = JSON.parse(text);
      if (isEnvelope(parsed) && parsed.entries.length > 0) {
        editorClipboard.entries = parsed.entries;
      }
    }
  } catch {
    // Read permission denied or non-JSON content: use the internal entries.
  }
  return pasteAtPlayhead(engine);
}

